.heading{color:#f5f5f5;text-align:center;font-size:1.3em}.heading--small{font-size:1em}.banner-image{opacity:0;width:100vw}@media(min-width: 600px){.banner-image{height:260px;width:390px;border:8px solid #f5f5f5;border-radius:5px}}.banner-image--fade-in{transition:opacity .5s ease-in;opacity:1}.hr{width:100%}