.exercise-card-title-wrapper{align-items:flex-start}.exercise-card{padding-bottom:10px}.exercise-card-title{width:80%}.exercise-card.v-sheet--outlined{border:solid 1px var(--v-primary-base)}.exercise-card.v-sheet--outlined.sortable-chosen{border:1px solid #d3d3d3;animation:blink .5s step-end infinite alternate}.exercise-card.v-sheet--outlined.drop-placeholder-exercise{border:solid 1px var(--v-warning-base)}@keyframes blink{50%{border:solid 1px var(--v-warning-base)}}